<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> now </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Instant</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">now</span><span style="color:#9399B2;">();</span></span>
