<span class="line"><span style="color:#F38BA8;">        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">last_render </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Instant</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">now</span><span style="color:#9399B2;">();</span></span>
